const html = $input.first().json.data;
const pageIndex = $('페이지 초기화').first().json.pageIndex 
  || $('다음 페이지 이동').first().json.pageIndex
  || 1;

// goView('V202600006') 패턴에서 plcyBizId 추출
const regex = /goView\('([A-Z]\d+)'\)/g;
const ids = [];
let match;
while ((match = regex.exec(html)) !== null) {
  ids.push(match[1]);
}

// 마지막 페이지 번호 추출: fn_egov_link_page(67) 에서 최대값
const pageRegex = /fn_egov_link_page\((\d+)\)/g;
let maxPage = 1;
let pageMatch;
while ((pageMatch = pageRegex.exec(html)) !== null) {
  const p = parseInt(pageMatch[1]);
  if (p > maxPage) maxPage = p;
}

// 총 건수 추출: (총 <strong class="fc-blue">332</strong>건)
const totalMatch = html.match(/총\s*<strong[^>]*>(\d+)<\/strong>\s*건/);
const totalCount = totalMatch ? parseInt(totalMatch[1]) : 0;

const items = ids.map(id => ({
  json: {
    plcyBizId: id,
    currentPage: pageIndex,
    lastPage: maxPage,
    totalCount: totalCount
  }
}));

if (items.length === 0) {
  return [{ json: { empty: true, currentPage: pageIndex, lastPage: maxPage } }];
}

return items;

const html = $input.first().json.data;
const plcyBizId = $('정책별 순차 처리').first().json.plcyBizId;

// Helper: th 텍스트로 인접 td 내용 추출
function extractByTh(thText) {
  // <th ...>thText</th> 다음에 오는 <td ...>내용</td> 추출
  const escapedTh = thText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const regex = new RegExp(
    '<th[^>]*>' + escapedTh + '</th>\\s*<td[^>]*>([\\s\\S]*?)</td>',
    'i'
  );
  const match = html.match(regex);
  if (!match) return '';
  // HTML 태그 제거, 공백 정리
  return match[1]
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\t/g, '')
    .replace(/\n\s*\n/g, '\n')
    .trim();
}

// 제목 추출: <strong class="title">...</strong>
const titleMatch = html.match(/<strong\s+class="title">([^<]+)<\/strong>/);
const title = titleMatch ? titleMatch[1].trim() : '';

// 정책 유형 (카테고리)
const category = extractByTh('정책 유형');

// 주관 기관
const organization = extractByTh('주관 기관');

// 정책 소개
const introduction = extractByTh('정책 소개');

// 지원 내용
const supportContent = extractByTh('지원 내용');

// 신청기간 파싱
const periodText = extractByTh('사업신청기간');
let applyStart = null;
let applyEnd = null;

if (periodText) {
  // "2026.4.1.(수)" 또는 "2026. 3. 6.(금)" 패턴 (점 뒤 공백 허용)
  const dateRegex = /(\d{4})\.\s*(\d{1,2})\.\s*(\d{1,2})/g;
  const dates = [];
  let dm;
  while ((dm = dateRegex.exec(periodText)) !== null) {
    const y = dm[1];
    const m = dm[2].padStart(2, '0');
    const d = dm[3].padStart(2, '0');
    dates.push(`${y}-${m}-${d}`);
  }
  if (dates.length >= 1) applyStart = dates[0];
  if (dates.length >= 2) applyEnd = dates[1];
}

// 연령/자격
const ageInfo = extractByTh('연령');

// 신청절차
const procedure = extractByTh('신청절차');

// 제출서류
const documents = extractByTh('제출서류');

// 본문 조합
const bodyParts = [];
if (introduction) bodyParts.push('사업개요: ' + introduction);
if (ageInfo) bodyParts.push('지원대상: ' + ageInfo);
if (supportContent) bodyParts.push('지원내용: ' + supportContent);
if (procedure) bodyParts.push('신청방법: ' + procedure);
if (documents) bodyParts.push('제출서류: ' + documents);

const body = bodyParts.join('\n');

// 카테고리 매핑 (한글 → 백엔드가 기대하는 한글 그대로 전달)
const sourceUrl = `https://youth.seoul.go.kr/infoData/plcyInfo/view.do?plcyBizId=${plcyBizId}&tab=001&key=2309150002&tabKind=002`;

const result = {
  source: {
    url: sourceUrl,
    type: 'YOUTH_SEOUL',
    fetchedAt: new Date().toISOString().replace('Z', '')
  },
  rawData: {
    title: title,
    body: body,
    category: category || '복지',
    region: '서울',
    applyStart: applyStart,
    applyEnd: applyEnd
  }
};

return [{ json: result }];

// 현재 배치의 정책 정보에서 페이지 정보 가져오기
const items = $('plcyBizId 추출').all();
const firstItem = items[0]?.json || {};
const currentPage = firstItem.currentPage || 1;
const lastPage = firstItem.lastPage || 1;

if (currentPage < lastPage) {
  // 다음 페이지로 이동
  return [{ json: { pageIndex: currentPage + 1, hasNext: true } }];
} else {
  // 모든 페이지 처리 완료
  return [{ json: { pageIndex: currentPage, hasNext: false } }];
}

const items = $('plcyBizId 추출').all();
const firstItem = items[0]?.json || {};
const totalCount = firstItem.totalCount || 0;
const lastPage = firstItem.lastPage || 0;

return [{
  json: {
    message: '크롤링 완료',
    totalPolicies: totalCount,
    totalPages: lastPage,
    completedAt: new Date().toISOString()
  }
}];
